// src/pages/YearSelection.js
import React from 'react';
import { useParams, useNavigate } from 'react-router-dom';

const YearSelection = () => {
  const { courseId } = useParams();
  const navigate = useNavigate();
  
  const handleBack = () => {
    navigate('/');
  };
  
  const handleYearClick = (year) => {
    navigate(`/course/${courseId}/year/${year}`);
  };
  
  return (
    <div style={styles.container}>
      <button onClick={handleBack} style={styles.backButton}>
        ← Back to Courses
      </button>
      
      <div style={styles.header}>
        <h1>Course {courseId} - Select Year</h1>
        <p>Choose your academic year</p>
      </div>
      
      <div style={styles.yearsGrid}>
        {[1, 2, 3, 4].map(year => (
          <div 
            key={year}
            style={styles.yearCard}
            onClick={() => handleYearClick(year)}
          >
            <div style={styles.yearNumber}>{year}</div>
            <h3>Year {year}</h3>
            <p>Complete study materials</p>
            <button style={styles.selectButton}>
              Select Year {year} →
            </button>
          </div>
        ))}
      </div>
    </div>
  );
};

const styles = {
  container: {
    maxWidth: '1200px',
    margin: '0 auto',
    padding: '2rem 1rem',
    minHeight: '100vh'
  },
  backButton: {
    padding: '0.75rem 1.5rem',
    background: '#4f46e5',
    color: 'white',
    border: 'none',
    borderRadius: '8px',
    cursor: 'pointer',
    marginBottom: '2rem'
  },
  header: {
    textAlign: 'center',
    marginBottom: '3rem',
    padding: '2rem',
    background: 'white',
    borderRadius: '15px',
    boxShadow: '0 5px 15px rgba(0,0,0,0.05)'
  },
  yearsGrid: {
    display: 'grid',
    gridTemplateColumns: 'repeat(auto-fill, minmax(250px, 1fr))',
    gap: '1.5rem'
  },
  yearCard: {
    background: 'white',
    padding: '1.5rem',
    borderRadius: '12px',
    textAlign: 'center',
    cursor: 'pointer',
    transition: 'all 0.3s',
    boxShadow: '0 5px 15px rgba(0,0,0,0.05)',
    '&:hover': {
      transform: 'translateY(-5px)',
      boxShadow: '0 10px 25px rgba(0,0,0,0.1)'
    }
  },
  yearNumber: {
    width: '60px',
    height: '60px',
    background: 'linear-gradient(135deg, #4f46e5, #7c3aed)',
    borderRadius: '50%',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    margin: '0 auto 1rem',
    color: 'white',
    fontSize: '1.5rem',
    fontWeight: 'bold'
  },
  selectButton: {
    marginTop: '1rem',
    padding: '0.75rem 1.5rem',
    background: 'linear-gradient(90deg, #4f46e5, #7c3aed)',
    color: 'white',
    border: 'none',
    borderRadius: '8px',
    cursor: 'pointer',
    width: '100%'
  }
};

export default YearSelection;
